using System.Net;
using System.Net.Http;
using System.Windows.Forms;
class ImageLoader
{
    void LoadImage(PictureBox pictureBox, string url)
    {
        // .NET 9: PictureBox.Load uses HttpClient internally and throws
        // HttpRequestException instead of WebException.
        try { pictureBox.Load(url); }
        catch (HttpRequestException ex) { Console.WriteLine("Failed: " + ex.Message); }
        catch (WebException ex) { Console.WriteLine("Failed: " + ex.Message); }
    }
}

